1930→/// - Generates `max(call_count_estimate, 1)` return values (for loop support)
1931→/// - Uses category-aware shaping when `return_type` is `Unknown`
1932→/// - Produces both success and error variants for declared error types
1933→///   (`Complex { kind: Result, .. }` or unions containing `Complex { kind: Error, .. }`)
1934→pub fn generate_mock_values(
1935→    mock_params: &[MockParam],
1936→    rng: &mut impl Rng,
1937→    caps: Option<&FrontendCapabilities>,
1938→) -> Vec<MockConfig> {
1939→    mock_params
1940→        .iter()
1941→        .map(|mp| {
1942→            let count = (mp.call_count_estimate as usize).max(1);
1943→            let (return_values, behavior) =
1944→                generate_mock_return_values(&mp.return_type, mp.category, count, rng, caps);
1945→
1946→            MockConfig {
1947→                symbol: mp.symbol.clone(),
1948→                return_values,
1949→                should_track_calls: true,
1950→                default_behavior: behavior,
1951→            }
1952→        })
1953→        .collect()
1954→}
1955→
1956→/// Generate return values for a single mock, dispatching to error-aware or
1957→/// category-shaped generators as needed.
1958→fn generate_mock_return_values(
1959→    return_type: &TypeInfo,
1960→    category: IoCategory,
1961→    count: usize,
1962→    rng: &mut impl Rng,
1963→    caps: Option<&FrontendCapabilities>,
1964→) -> (Vec<Value>, MockBehavior) {
1965→    // Result complex type: alternates ok/err variants using the tagged wire format.
1966→    if matches!(return_type, TypeInfo::Complex { kind: ComplexKind::Result, .. }) {
1967→        let values = (0..count)
1968→            .map(|i| {
1969→                if i % 2 == 0 {
1970→                    let inner = generate_random_value(&TypeInfo::Unknown, rng, caps);
1971→                    json!({"__complex_type": "result", "ok": true, "value": inner})
1972→                } else {
1973→                    json!({"__complex_type": "result", "ok": false, "value": "mock error"})
1974→                }
1975→            })
1976→            .collect();
1977→        return (values, MockBehavior::ReturnGenerated);
